IF OBJECT_ID(N'cacsms.CollaborationAssignmentEngineSettings','U') IS NULL CREATE TABLE cacsms.CollaborationAssignmentEngineSettings(WorkspaceId uniqueidentifier NOT NULL PRIMARY KEY,Enabled bit NOT NULL DEFAULT(1),NextRebalanceAt datetimeoffset NULL,UpdatedAt datetimeoffset NOT NULL DEFAULT(SYSUTCDATETIME()));
IF OBJECT_ID(N'cacsms.CollaborationAssignmentEngineEvents','U') IS NULL CREATE TABLE cacsms.CollaborationAssignmentEngineEvents(EventId uniqueidentifier NOT NULL PRIMARY KEY DEFAULT NEWSEQUENTIALID(),WorkspaceId uniqueidentifier NOT NULL,Action nvarchar(30) NOT NULL,CreatedAt datetimeoffset NOT NULL DEFAULT(SYSUTCDATETIME()));
IF NOT EXISTS(SELECT 1 FROM cacsms.CollaborationAssignmentEngineSettings s JOIN cacsms.Workspaces w ON w.WorkspaceId=s.WorkspaceId WHERE w.Status=N'active') INSERT cacsms.CollaborationAssignmentEngineSettings(WorkspaceId,NextRebalanceAt) SELECT TOP(1) WorkspaceId,DATEADD(SECOND,30,SYSUTCDATETIME()) FROM cacsms.Workspaces WHERE Status=N'active' ORDER BY CreatedAt;
